import { useEffect, useRef, useState } from 'react';
import './events.css';

const events = [
  {
    title: 'Community Food Drive',
    date: '12 Aug 2026',
    venue: 'Town Hall, Salem',
    seats: '45 seats left',
    raised: 38000,
    goal: 50000,
    image:
      'https://images.unsplash.com/photo-1484712401471-05c7215830eb?auto=format&fit=crop&w=900&q=80',
  },
  {
    title: 'Back to School Kit Camp',
    date: '24 Aug 2026',
    venue: 'Nehru School',
    seats: '20 seats left',
    raised: 14500,
    goal: 25000,
    image:
      'https://images.unsplash.com/photo-1497486751825-1233686d5d80?auto=format&fit=crop&w=900&q=80',
  },
  {
    title: 'Health Awareness Rally',
    date: '04 Sep 2026',
    venue: 'Fort Grounds',
    seats: '60 seats left',
    raised: 27000,
    goal: 40000,
    image:
      'https://images.unsplash.com/photo-1516549655169-df83a0774514?auto=format&fit=crop&w=900&q=80',
  },
];

function formatINR(n) {
  return '₹' + n.toLocaleString('en-IN');
}

/* Animates the bar width from 0 → target% on mount */
function ProgressBar({ raised, goal }) {
  const pct = Math.min(Math.round((raised / goal) * 100), 100);
  const [width, setWidth] = useState(0);
  const ref = useRef(null);

  useEffect(() => {
    // Trigger fill animation after a short paint delay
    const id = setTimeout(() => setWidth(pct), 120);
    return () => clearTimeout(id);
  }, [pct]);

  return (
    <>
      <div className="donation-meta">
        <span className="raised">{formatINR(raised)} raised</span>
        <span className="pct">{pct}%</span>
        <span className="goal">of {formatINR(goal)}</span>
      </div>
      <div className="event-progress-track" ref={ref}>
        <div
          className="event-progress-fill"
          style={{ width: `${width}%` }}
          role="progressbar"
          aria-valuenow={pct}
          aria-valuemin={0}
          aria-valuemax={100}
        />
      </div>
    </>
  );
}

export default function Events() {
  return (
    <>
      <section className="page-hero">
        <div className="container">
          <h1>Events</h1>
          <p>Join our upcoming community participation drives.</p>
        </div>
      </section>

      <section className="page-content container">
        <div className="section-title">
          <h2>Upcoming Events</h2>
        </div>

        <div className="event-grid">
          {events.map((event) => (
            <div className="event-card" key={event.title}>
              {/* ── Donation progress bar ── */}
              <div style={{ padding: '16px 20px 0' }}>
                <ProgressBar raised={event.raised} goal={event.goal} />
              </div>

              <img src={event.image} alt={event.title} />

              <div className="content">
                <h3>{event.title}</h3>
                <p><strong>Date:</strong> {event.date}</p>
                <p><strong>Venue:</strong> {event.venue}</p>
                <p><strong>Seats:</strong> {event.seats}</p>
                <a href="/donate" className="btn btn-primary">Donate Now</a>
              </div>
            </div>
          ))}
        </div>
      </section>
    </>
  );
}
